#include<bits/stdc++.h>
#define LL long long
using namespace std;
string L,R;
LL n,ch,dp[20][200][200][2][2],ans;
void init(int N){
  for(int i=0;i<=n;i++)for(int j=0;j<=N;j++)
    for(int k=0;k<=N;k++)for(int x=0;x<2;x++)
      for(int y=0;y<2;y++)dp[i][j][k][x][y]=0;
  dp[0][0][0][0][0]=1;return;
}
int main(){
  cin>>L>>R;n=R.size(),ch=n-L.size();
  while(L.size()<n)L="0"+L;
  for(int mod=1;mod<=n*9;mod++){
    init(mod);
    for(int i=0;i<n;i++)for(int f=0;f<=mod;f++)
      for(int x=0;x<2;x++)for(int y=0;y<2;y++)for(int p=0;p<=mod;p++)
          for(int k=(x?0:L[i]-'0');k<=(y?9:R[i]-'0')&&f+k<=mod;k++){
            if(!dp[i][f][p][x][y])continue;
            int u=(x||k>(L[i]-'0')),v=(y||k<(R[i]-'0'));
            dp[i+1][f+k][(p*10+k)%mod][u][v]+=dp[i][f][p][x][y];
          }
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)ans+=dp[n][mod][0][x][y];
  }
  cout<<ans<<"\n";
  return 0;
}
